static int em_check_path_traversal(const char *val) {
    if (val == NULL || val[0] == '\0')
        return 0;
    /* Detect directory traversal patterns */
    if (strstr(val, "../") != NULL) return 1;
    if (strstr(val, "..\\") != NULL) return 1;
    if (strstr(val, "..%2f") != NULL) return 1;
    if (strstr(val, "..%2F") != NULL) return 1;
    if (strstr(val, "..%252f") != NULL) return 1;
    if (strstr(val, "/etc/") != NULL) return 1;
    if (strstr(val, "\\windows\\") != NULL) return 1;
    return 0;
}
